        cin >> n >> x;
        vector<int> pre[3];
        for (int i = 0; i < 3; i++) {
            int s = 0;
            pre[i].push_back(s);
            for (int j = 0; j < n; j++) {
                cin >> ai;
                if ((s | ai) != s)
                    s |= ai, pre[i].push_back(s);
            }
        }
        bool ans = 0;
        for (int A : pre[0]) for (int B : pre[1]) for (int C : pre[2])
            ans |= (A | B | C) == x;
        cout << (ans ? "YES\n" : "NO\n");
    }
}

